import {
  Container,
  Typography,
  Card,
  CardContent,
  Box,
} from "@mui/material";

import "./BoardPage.css";

function BoardPage() {
  const posts = [
    {
      id: 1,
      title: "공지사항",
      author: "관리자",
      content: "게시판 테스트입니다.",
    },
    {
      id: 2,
      title: "React 공부",
      author: "홍길동",
      content: "Material UI와 CSS를 적용 중입니다.",
    },
    {
      id: 3,
      title: "Flask 연동 예정",
      author: "김철수",
      content: "백엔드와 API 연결 예정입니다.",
    },
  ];

  return (
    <Container className="board-container">

      {/* 상단 헤더 */}
      <Box className="board-header">
        <Typography
          variant="h4"
          className="board-title"
        >
          KLAS 게시판
        </Typography>

        <Typography className="board-subtitle">
          공지사항 및 게시글 목록
        </Typography>
      </Box>

      {/* 게시글 카드 */}
      {posts.map((post) => (
        <Card
          key={post.id}
          className="board-card"
          sx={{ mb: 3 }}
        >
          <CardContent>

            <Typography
              variant="h5"
              className="board-post-title"
            >
              {post.title}
            </Typography>

            <Typography className="board-author">
              작성자: {post.author}
            </Typography>

            <Typography className="board-content">
              {post.content}
            </Typography>

          </CardContent>
        </Card>
      ))}
    </Container>
  );
}

export default BoardPage;
